module mux_forwarding(  
    input [4:0] data_in_1,  
    input [4:0] b,  
    input sel,  
    input forward_en,  
    output reg [4:0] y  
);  
    always @(*) begin  
        if (forward_en)  
            y = data_in_1;  
        else  
            y = sel ? b : data_in_1;  
    end  
endmodule
